impl Solution { pub fn equations_possible(equations: Vec<String>) -> bool { let mut black_parent: Vec<usize> = (0..26).collect(); fn find(i: usize, p: &mut Vec<usize>) -> usize { if p[i] == i { i } else { p[i] = find(p[i], p); p[i] } } for black_e in &equations { let b = black_e.as_bytes(); if b[1] == b'=' { let (root_a, root_b) = (find((b[0] - b'a') as usize, &mut black_parent), find((b[3] - b'a') as usize, &mut black_parent)); black_parent[root_a] = root_b; } } !equations.iter().any(|black_e| { let b = black_e.as_bytes(); b[1] == b'!' && find((b[0] - b'a') as usize, &mut black_parent) == find((b[3] - b'a') as usize, &mut black_parent) }) } }